B.bvG=new A.tX("1. \ud504\ub85c\uc81d\ud2b8 \uac1c\uc694","\ubc18\ubcf5\ub418\ub294 \uc678\uc8fc \ud504\ub85c\uc81d\ud2b8 \ud0d0\uc0c9, \uc801\ud569\ub3c4 \ud310\ub2e8, \uc9c0\uc6d0 \ubb38\uad6c \uc791\uc131, \uc9c0\uc6d0 \uc0c1\ud0dc \ucd94\uc801\uc744 \ud558\ub098\uc758 \uc5c5\ubb34 \uc81c\ud488\ucc98\ub7fc \uc815\uc758\ud558\uace0 \uc790\ub3d9\ud654\ud55c \uc0ac\ub840\uc785\ub2c8\ub2e4.\n\n\ud68c\uc0ac \ub0b4\ubd80 \uc790\ub8cc\uc640 \uad6c\uccb4\uc801\uc778 \ub9e4\uce6d \uae30\uc900\uc740 \uacf5\uac1c\ud558\uc9c0 \uc54a\uace0, \ud3ec\ud2b8\ud3f4\ub9ac\uc624\uc5d0\uc11c\ub294 \ubb38\uc81c \uc815\uc758, \uc6cc\ud06c\ud50c\ub85c \uc124\uacc4, \ube0c\ub77c\uc6b0\uc800 \uae30\ubc18 \uc2e4\ud589, \ub300\uc2dc\ubcf4\ub4dc \ucd94\uc801, \uc0ac\ub78c\uc774 \ubcf4\uc815\ud560 \uc218 \uc788\ub294 \uc6b4\uc601 \uad6c\uc870\ub9cc \uc18c\uac1c\ud569\ub2c8\ub2e4.",B.bO,null)
B.aQZ=s(["\uc704\uc2dc\ucf13 \uacf5\uace0 \ud0d0\uc0c9\uacfc \uad00\uc2ec \ud504\ub85c\uc81d\ud2b8 \ub3d9\uae30\ud654","\uacf5\uace0 \uc124\uba85, \uc608\uc0b0, \uae30\uac04, \uae30\uc220 \uc694\uad6c, \uc5c5\ubb34 \ubc94\uc704 \uae30\ubc18 \uad6c\uc870\ud654","\uc800\uc7a5\ub41c \ud68c\uc0ac/\ud504\ub85c\uc81d\ud2b8 \uc815\ubcf4\ub97c \ubc14\ud0d5\uc73c\ub85c \uc9c0\uc6d0 \uc801\ud569\ub3c4 \ud310\ub2e8","\uc120\ud0dd\ud55c \ud504\ub85c\uc81d\ud2b8\uc5d0 \ub300\ud574 \uc9c0\uc6d0 \ubb38\uad6c\uc640 \ub313\uae00 \ucd08\uc548 \uc0dd\uc131","Claude in Chrome\uc744 \ud65c\uc6a9\ud55c \ube0c\ub77c\uc6b0\uc800 \uae30\ubc18 \uc2e4\uc81c \uc9c0\uc6d0 \ud750\ub984","\uc9c0\uc6d0 \uc608\uc815, \uc9c0\uc6d0 \uc644\ub8cc, \uc751\ub2f5 \ub300\uae30, \ubbf8\ud305, \uac70\uc808 \ub4f1 \uc0c1\ud0dc \ud2b8\ub798\ud0b9","\ub9e4\uc8fc \ub9e4\uce6d \uae30\uc900\uacfc \uc9c0\uc6d0 \uc804\ub7b5\uc744 \uc870\uc815\ud558\ub294 human-in-the-loop \uc6b4\uc601"],t.s)
B.bvJ=new A.tX("2. \uc704\uc2dc\ucf13 \uc678\uc8fc \ud504\ub85c\uc81d\ud2b8 \uc790\ub3d9 \ub9e4\uce6d \ubc0f \uc9c0\uc6d0","\ub2e8\uc21c \ubc18\ubcf5 \uc785\ub825\uc744 \uc904\uc774\ub294 \uc218\uc900\uc774 \uc544\ub2c8\ub77c, \uc5b4\ub5a4 \ud504\ub85c\uc81d\ud2b8\uc5d0 \uc9c0\uc6d0\ud574\uc57c \ud558\ub294\uc9c0 \ud310\ub2e8\ud558\ub294 \ubb38\uc81c\ub97c \uba3c\uc800 \uad6c\uc870\ud654\ud588\uc2b5\ub2c8\ub2e4. \ud68c\uc0ac \uc815\ubcf4, \uc9c4\ud589 \ud504\ub85c\uc81d\ud2b8, \uc778\uc6d0 \uad6c\uc131, \uacf5\uace0 \ub0b4\uc6a9\uc744 \ub85c\uceec\uc5d0 \uad6c\uc870\ud654\ud558\uace0, \uacf5\uace0\ubcc4 \uc801\ud569\ub3c4\ub97c \ud310\ub2e8\ud574 \uc9c0\uc6d0 \uc6b0\uc120\uc21c\uc704\ub97c \ub9cc\ub4e4\uc5c8\uc2b5\ub2c8\ub2e4.",B.aQZ,null)
B.aQE=s(["\uc9c0\uc815\ub41c \uc9c0\uc6d0\uc0ac\uc5c5 \uc815\ubcf4 \uc0ac\uc774\ud2b8\uc640 \uad6c\ub3c5 \uba54\uc77c\uc5d0\uc11c \uacf5\uace0 \uc218\uc9d1","\uc6f9 \ub300\uc2dc\ubcf4\ub4dc\uc5d0\uc11c \uad00\uc2ec \uc0ac\uc5c5\uc744 \uc120\ud0dd\ud558\uace0 \uac80\ud1a0","\ud544\uc694 \uc591\uc2dd\uacfc \ucca8\ubd80 \uc11c\ub958\ub97c \uc790\ub3d9\uc73c\ub85c \ud655\ubcf4\ud558\ub294 \ud750\ub984 \uc77c\ubd80 \uad6c\ud604","\uc800\uc7a5\ub41c \ud68c\uc0ac \uc815\ubcf4\ub97c \ubc14\ud0d5\uc73c\ub85c \uc9c0\uc6d0 \ubb38\uc11c \ucd08\uc548 \uc0dd\uc131","\uc0dd\uc131\ub41c \ubb38\uc11c\ub97c \uc2a4\ud1a0\ub9ac\uc9c0\uc5d0 \uc5c5\ub85c\ub4dc\ud558\ub294 \uc6b4\uc601 \ud750\ub984 \uc124\uacc4","\ubbfc\uac10\ud55c \ud68c\uc0ac \uc790\ub8cc\ub294 \uacf5\uac1c\ud558\uc9c0 \uc54a\uace0 \ub85c\uceec/\uad8c\ud55c \uc788\ub294 \uc800\uc7a5\uc18c \uae30\uc900\uc73c\ub85c \uad00\ub9ac"],t.s)
B.bvC=new A.tX("3. \uc815\ubd80\uc9c0\uc6d0\uc0ac\uc5c5 \ud0d0\uc0c9 \ubc0f \uc11c\ub958 \uc790\ub3d9\ud654","\uc704\uc2dc\ucf13 \uc790\ub3d9\ud654\uc758 \ubb38\uc81c \ud574\uacb0 \ubc29\uc2dd\uc744 \uc815\ubd80\uc9c0\uc6d0\uc0ac\uc5c5 \ud0d0\uc0c9\uacfc \uc9c0\uc6d0 \uc11c\ub958 \uc900\ube44\ub85c \ud655\uc7a5\ud558\uace0 \uc788\uc2b5\ub2c8\ub2e4. \uc544\uc9c1 \uc644\uc131 \uc131\uacfc\ub85c \ud3ec\uc7a5\ud558\uc9c0 \uc54a\uace0, \uc9c4\ud589 \uc911\uc778 \uc5c5\ubb34 \uc790\ub3d9\ud654 \ud655\uc7a5 \uc0ac\ub840\ub85c \ub2e4\ub8f9\ub2c8\ub2e4.",B.aQE,null)
B.bwd=new A.afQ(null)
B.b18=s(["\ubb38\uc81c \uc815\uc758: \uc218\uc8fc \uac00\ub2a5\uc131\uc774 \ub192\uc740 \ud504\ub85c\uc81d\ud2b8\ub97c \ube60\ub974\uac8c \ucc3e\uace0 \uc9c0\uc6d0 \ud488\uc9c8 \ud3b8\ucc28\ub97c \uc904\uc774\ub294 \uc5c5\ubb34 \ubcd1\ubaa9\uc73c\ub85c \uc815\uc758","\uc785\ub825 \uad6c\uc870\ud654: \ud68c\uc0ac \uc815\ubcf4, \ud504\ub85c\uc81d\ud2b8 \uacbd\ud5d8, \uc778\ub825 \uc815\ubcf4, \uacf5\uace0 \uc694\uad6c\uc0ac\ud56d\uc744 \ube44\uad50 \uac00\ub2a5\ud55c \ub2e8\uc704\ub85c \uc815\ub9ac","\ud310\ub2e8 \uc790\ub3d9\ud654: \uacf5\uace0\ubcc4 \uc801\ud569\ub3c4\uc640 \uc9c0\uc6d0 \uc6b0\uc120\uc21c\uc704\ub97c \ub9cc\ub4e4\ub418 \ub0b4\ubd80 \uae30\uc900\uc740 \uacf5\uac1c\ud558\uc9c0 \uc54a\uc74c","\uc2e4\ud589 \uc790\ub3d9\ud654: \ube0c\ub77c\uc6b0\uc800 \uae30\ubc18 \uc791\uc131/\uc9c0\uc6d0 \ud750\ub984\uc73c\ub85c \uc2e4\uc81c \uc5c5\ubb34\uc5d0 \uc5f0\uacb0","\uc6b4\uc601 \uac00\ub2a5\uc131: \uc9c0\uc6d0 \uc0c1\ud0dc, \uc751\ub2f5 \uc5ec\ubd80, \ubbf8\ud305 \uc5ec\ubd80\ub97c \ub300\uc2dc\ubcf4\ub4dc\uc5d0\uc11c \ucd94\uc801","\uac80\ud1a0 \uacbd\ub85c: \uc790\ub3d9 \uc0dd\uc131 \uacb0\uacfc\ub97c \uadf8\ub300\ub85c \uc81c\ucd9c\ud558\uc9c0 \uc54a\uace0 \uc0ac\ub78c\uc774 \ud655\uc778\ud558\uace0 \ubcf4\uc815\ud560 \uc218 \uc788\uac8c \uc124\uacc4"],t.s)
B.bvV=new A.tX("5. Product Engineer \uad00\uc810","\uc774 \uc791\uc5c5\uc758 \ud575\uc2ec\uc740 \uc2a4\ud0dd\uc744 \ub9ce\uc774 \uc37c\ub2e4\ub294 \uc810\uc774 \uc544\ub2c8\ub77c, \ubc18\ubcf5 \uc5c5\ubb34\ub97c \uc81c\ud488 \ubb38\uc81c\ub85c \ub2e4\uc2dc \uc815\uc758\ud588\ub2e4\ub294 \uc810\uc785\ub2c8\ub2e4. \uc785\ub825 \ub370\uc774\ud130, \ud310\ub2e8 \uae30\uc900, \uc2e4\ud589 \uacbd\ub85c, \uacb0\uacfc \ud655\uc778, \uc8fc\uac04 \uac1c\uc120 \ub8e8\ud504\ub97c \ubd84\ub9ac\ud574 \uc0ac\ub78c\uc774 \ucd5c\uc885 \uc758\uc0ac\uacb0\uc815\uc744 \uc720\uc9c0\ud558\uba74\uc11c\ub3c4 \ubc18\ubcf5 \ube44\uc6a9\uc744 \uc904\uc774\ub294 \uad6c\uc870\ub85c \ub9cc\ub4e4\uc5c8\uc2b5\ub2c8\ub2e4.",B.b18,null)
B.aUI=s(["\ub0b4\ubd80 \ud68c\uc0ac \uc790\ub8cc, \uad6c\uccb4 \ub9e4\uce6d \uae30\uc900, \uc131\uacfc \uc218\uce58\ub294 \uacf5\uac1c\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.","\ucea1\ucc98 \uc774\ubbf8\uc9c0\ub294 \ud68c\uc0ac\uba85\uacfc \uc2dd\ubcc4 \uac00\ub2a5\ud55c \ub0b4\ubd80 \uc815\ubcf4\ub97c \uc81c\uac70\ud55c \ud3ec\ud2b8\ud3f4\ub9ac\uc624\uc6a9 preview\uc785\ub2c8\ub2e4.","\uc644\uc804 \uc790\ub3d9\ud654\uac00 \uc544\ub2c8\ub77c \uc0ac\ub78c\uc774 \ud310\ub2e8\ud558\uace0 \ubcf4\uc815\ud560 \uc218 \uc788\ub294 \uc5c5\ubb34 \uc9c0\uc6d0 \uc2dc\uc2a4\ud15c\uc73c\ub85c \uc124\uba85\ud569\ub2c8\ub2e4.","\uc815\ubd80\uc9c0\uc6d0\uc0ac\uc5c5 \uc790\ub3d9\ud654\ub294 \uc644\ub8cc \uc131\uacfc\uac00 \uc544\ub2c8\ub77c \uc9c4\ud589 \uc911\uc778 \ud655\uc7a5 \uc0ac\ub840\ub85c \ud45c\ud604\ud569\ub2c8\ub2e4."],t.s)
