B.bvp=new A.Ow("2. Model Court YouTube Shorts \uc790\ub3d9\ud654","FinalSay \uc571\uc744 \uc9c1\uc811 \ud64d\ubcf4\ud558\uae30 \uc804\uc5d0, AI\uac00 \uc0dd\ud65c\ud615 \ub17c\uc7c1\uc744 \ud310\uacb0\ud558\ub294 \uc20f\ud3fc \ucf58\ud150\uce20 IP\ub97c \uac80\uc99d\ud558\uace0 \uc2f6\uc5c8\uc2b5\ub2c8\ub2e4. \ub2e8\ubc1c\uc131 \uc601\uc0c1 \uc81c\uc791\uc774 \uc544\ub2c8\ub77c \uc8fc\uc81c \uc120\uc815, \ub300\ubcf8, \ub80c\ub354\ub9c1, \uba54\ud0c0\ub370\uc774\ud130, \uc5c5\ub85c\ub4dc, \uae30\ub85d\uae4c\uc9c0 \ubc18\ubcf5 \uac00\ub2a5\ud55c \uad6c\uc870\uac00 \ud544\uc694\ud588\uc2b5\ub2c8\ub2e4.","MBTI\ub97c \uc2e4\uc81c \uc2ec\ub9ac \uc9c4\ub2e8\uc774 \uc544\ub2cc \uc5d4\ud130\ud14c\uc778\uba3c\ud2b8\uc6a9 \uce90\ub9ad\ud130 \ud504\ub808\uc774\ubc0d\uc73c\ub85c \uc0ac\uc6a9\ud574, \ub450 \uce90\ub9ad\ud130\uac00 \uc9e7\uac8c \ud1a0\ub860\ud558\uace0 \ub9c8\uc9c0\ub9c9\uc5d0 \ud310\uacb0\uc774 \ub098\ub294 \uc1fc\uce20 \ud3ec\ub9f7\uc744 \uc124\uacc4\ud588\uc2b5\ub2c8\ub2e4. \ud398\ub974\uc18c\ub098 JSON, \ub300\ubcf8 \uc0dd\uc131, TTS, \uc790\ub9c9, \ucef7 \uc804\ud658, \uc810\uc218\ud310, \ud310\uacb0 \ud654\uba74, BGM/SFX \ud569\uc131\uc744 MoviePy \uae30\ubc18 \ud30c\uc774\ud504\ub77c\uc778\uc73c\ub85c \uc5f0\uacb0\ud588\uc2b5\ub2c8\ub2e4.","\uc601\uc0c1\ubcc4 sidecar metadata JSON\uc73c\ub85c \uc81c\ubaa9, \uc124\uba85, \ud0dc\uadf8, \uce74\ud14c\uace0\ub9ac, made_for_kids \uc5ec\ubd80, topic, matchup, winner\ub97c \uad00\ub9ac\ud588\uc2b5\ub2c8\ub2e4. YouTube Data API \uc5c5\ub85c\ub4dc, upload_history.jsonl \uae30\ub85d, uploaded_topics.json \uc911\ubcf5 \ubc29\uc9c0, mbti_league.json \uc2b9\ud328 \ub204\uc801, Analytics \uc870\ud68c\uc6a9 \ud1a0\ud070 \ubd84\ub9ac\uae4c\uc9c0 \uc6b4\uc601 \ub9ac\uc2a4\ud06c\ub97c \ubc18\uc601\ud588\uc2b5\ub2c8\ub2e4.","\ucf58\ud150\uce20 \ud3ec\ub9f7 \uc124\uacc4, MBTI \ud398\ub974\uc18c\ub098 \ub370\uc774\ud130 \ubaa8\ub378\ub9c1, \ud504\ub86c\ud504\ud2b8 \ud1a4 \uac00\uc774\ub4dc, \ub80c\ub354\ub9c1 \uc2a4\ud06c\ub9bd\ud2b8, \uc5c5\ub85c\ub4dc \uc2a4\ud06c\ub9bd\ud2b8, \uc911\ubcf5 \ubc29\uc9c0, \ub77c\uc774\uc120\uc2a4 \ud45c\uae30 \uaddc\uce59, \uc870\ud68c \uc804\uc6a9 Analytics \uad6c\uc870\ub97c \uad6c\ud604\ud588\uc2b5\ub2c8\ub2e4.",B.b1V,null)
B.aSd=s(["\uc785\ub825 \uc218\uc9d1: RSS, \uc6b4\uc601 \uc124\uc815, \uce74\ud14c\uace0\ub9ac, \uad6d\uac00 \uc815\ubcf4\ub97c \uc815\uaddc\ud654","\uc0dd\uc131 \uacc4\uce35: OpenAI API\uc640 \ud504\ub86c\ud504\ud2b8 \uac00\uc774\ub4dc\ub85c \ud1a0\ub860 seed\uc640 \uc20f\ud3fc \ub300\ubcf8 \uc0dd\uc131","\uac80\uc99d \uacc4\uce35: \uc9c8\ubb38\ud615 \ubc18\ubcf5, \ucd94\uc0c1 \ud504\ub808\uc784, \uae30\uc0ac \uc81c\ubaa9 \ubcf5\ubd99, \uc57d\ud55c \ub17c\uc7c1 \uad6c\ub3c4\ub97c \uc904\uc774\ub294 \uaddc\uce59 \uc801\uc6a9","\uc0b0\ucd9c \uacc4\uce35: JSON payload, sidecar metadata, MP4, summary, upload history\ub97c \ud30c\uc77c\ub85c \ub0a8\uae40","\uc5c5\ub85c\ub4dc \uacc4\uce35: \ub0b4\ubd80 API\uc640 YouTube API\ub97c \ubd84\ub9ac\ud558\uace0 \uc2e4\ud328 \uc0ac\uc720\ub97c \uae30\ub85d","\uc6b4\uc601 \uacc4\uce35: \uc790\ub3d9 \uc2e4\ud589\uc744 \uae30\ubcf8\uc73c\ub85c \ud558\ub418 \uc0ac\ub78c\uc774 \ubcf4\uc815 payload\ub97c \ub123\uc744 \uc218 \uc788\ub294 human-in-the-loop \uad6c\uc870 \uc720\uc9c0"],t.s)
