B.aXQ=s(["\ucd5c\uadfc summary\uc758 source URL\uc744 \ud68c\ud53c\ud574 \uac19\uc740 \uae30\uc0ac \uae30\ubc18 \uc911\ubcf5 \uc0dd\uc131\uc744 \uc904\uc784","\uc0dd\uc131 \uc2e4\ud328 \uc2dc \uc2e4\ud328 \uc0ac\uc720\ub97c \uae30\ub85d\ud558\uace0 \uc2e4\ud328\ud55c \uad6d\uac00:\uce74\ud14c\uace0\ub9ac \uc870\ud569\ub9cc \ubd80\ubd84 \uc7ac\uc2e4\ud589","\uc790\uc5f0\uc2a4\ub7ec\uc6b4 \ud55c\uad6d\uc5b4 \uc1fc\uce20 \ud1a4\uc744 \uc704\ud574 \uc124\uba85\ubb38\ubcf4\ub2e4 \uc9e7\uc740 \ub300\uc0ac\uc640 \ubc18\ubc15 \uc911\uc2ec\uc73c\ub85c \ud504\ub86c\ud504\ud2b8 \uc870\uc815","YouTube \uc5c5\ub85c\ub4dc \ud1a0\ud070\uacfc Analytics \uc870\ud68c \ud1a0\ud070\uc744 \ubd84\ub9ac\ud574 \uad8c\ud55c \ubc94\uc704\ub97c \uad00\ub9ac","BGM \ucd9c\ucc98\uc640 CC BY \ub77c\uc774\uc120\uc2a4 \ud45c\uae30 \uaddc\uce59\uc744 \uc124\uba85\ub780\uacfc \ub85c\uceec \ub178\ud2b8\ub85c \ubd84\ub9ac"],t.s)
